	for name, c := range cases {
		t.Run(name, func(t *testing.T) {
			var params GetMetricDataInput
			serverURL := "http://localhost:8888/"
			client := New(Options{
				HTTPClient: smithyhttp.ClientDoFunc(func(r *http.Request) (*http.Response, error) {
					headers := http.Header{}
					for k, vs := range c.Header {
						for _, v := range vs {
							headers.Add(k, v)
						}
					}
					if len(c.BodyMediaType) != 0 && len(headers.Values("Content-Type")) == 0 {
						headers.Set("Content-Type", c.BodyMediaType)
					}
					response := &http.Response{
						StatusCode: c.StatusCode,
						Header:     headers,
						Request:    r,
					}
					if len(c.Body) != 0 {
						response.ContentLength = int64(len(c.Body))
						response.Body = ioutil.NopCloser(bytes.NewReader(c.Body))
					} else {

						response.Body = http.NoBody
					}
					return response, nil
				}),
				APIOptions: []func(*middleware.Stack) error{
					func(s *middleware.Stack) error {
						s.Finalize.Clear()
						s.Initialize.Remove(`OperationInputValidation`)
						return nil
					},
				},
				EndpointResolverV2: &protocolTestEndpointResolver{serverURL},
			})
			timings := make([]time.Duration, 0)
			benchmarkStart := time.Now()

			for i := 0; i < 10000; i++ {
				_, err := client.GetMetricData(context.Background(), &params, func(o *Options) {
					o.APIOptions = append(o.APIOptions, []func(*middleware.Stack) error{
						func(s *middleware.Stack) error {
							return s.Deserialize.Insert(middleware.DeserializeMiddlewareFunc("deserilaizerbenchmark", func(ctx context.Context, input middleware.DeserializeInput, next middleware.DeserializeHandler) (out middleware.DeserializeOutput, metadata middleware.Metadata, err error) {
								deserializeStart := time.Now()
								out, metadata, err = next.HandleDeserialize(ctx, input)
								deserializeEnd := time.Now()
								if i >= 1000 {
									timings = append(timings, deserializeEnd.Sub(deserializeStart))
								}
								return
							}), "OperationDeserializer", middleware.Before)
						},
					}...)
				})
				if err != nil {
					t.Fatalf("error when running deserd test for %s: %v", name, err)
				}
				if benchmarkStart.Add(30000000000).Before(time.Now()) {
					break
				}

			}
			mean := float64(0)
			n := len(timings)
			slices.Sort(timings)
			stddev := float64(0)
			for _, t := range timings {
				mean += float64(t) / float64(n)
			}
			p50 := timings[int64(float64(n-1)*0.5)]
			p90 := timings[int64(float64(n-1)*0.9)]
			p95 := timings[int64(float64(n-1)*0.95)]
			p99 := timings[int64(float64(n-1)*0.99)]
			for _, t := range timings {
				stddev += (float64(t) - mean) * (float64(t) - mean) / float64(n)
			}
			stddev = math.Sqrt(stddev)

			t.Logf("p50: %v\n", p50)
			t.Logf("p90: %v\n", p90)
			t.Logf("p95: %v\n", p95)
			t.Logf("p99: %v\n", p99)
			t.Logf("mean: %v ns\n", mean)
			t.Logf("stddev: %v\n", stddev)

			addSerdBenchmarkResult(serdBenchmarkResult{
				ID:     name,
				N:      n,
				Mean:   mean,
				P50:    float64(p50),
				P90:    float64(p90),
				P95:    float64(p95),
				P99:    float64(p99),
				StdDev: stddev,
			})

		})
	}
